10	interface Scenario {
11	  steps: Step[];
12	}
13	
14	const PROCESSING_FEE = 5;
15	const FIRST_INSURANCE_RATE = 0.1;
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	export function processScenario(scenario: Scenario): unknown {
26	  const items = scenario.steps[0].items;
27	
28	  const basePremium = items.reduce(
29	    (sum, item) => sum + BASE_PREMIUM[item.type],
30	    0,
31	  );
32	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
33	  const premium = Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
34	
35	  return [{ premium }];
36	}
